if(getcustom('lipinka_exchange_type')){
    if(!pdo_fieldexists2("ddwx_lipin","exchange_type")) {
        \think\facade\Db::execute("ALTER TABLE `ddwx_lipin` 
        ADD COLUMN `exchange_type` tinyint(1) DEFAULT '1' COMMENT '兑换模式 1：一码兑换一次 2：一码兑换多次';");
    }

    //礼品卡多次兑换记录
    \think\facade\Db::execute("CREATE TABLE IF NOT EXISTS `ddwx_lipin_exchange_record` (
        `id` int(11) NOT NULL AUTO_INCREMENT,
        `aid` int(11) DEFAULT NULL,
        `hid` int(11) DEFAULT NULL COMMENT '礼品卡id',
        `name` varchar(255) DEFAULT NULL COMMENT '礼品卡名称',
        `code_id` int(11) DEFAULT NULL COMMENT '兑换码id',
        `code` varchar(100) DEFAULT NULL COMMENT '兑换码',
        `mid` int(11) DEFAULT NULL COMMENT '会员id',
        `exchange_type` tinyint(1) DEFAULT '1' COMMENT '兑换模式 1：一码兑换一次 2：一码兑换多次',
        `nickname` varchar(255) DEFAULT NULL,
        `headimg` varchar(255) DEFAULT NULL,
        `remark` varchar(255) DEFAULT NULL,
        `createtime` int(11) DEFAULT NULL,
        PRIMARY KEY (`id`) USING BTREE,
        KEY `aid` (`aid`) USING BTREE,
        KEY `hid` (`hid`) USING BTREE,
        KEY `code_id` (`code_id`) USING BTREE,
        KEY `code` (`code`) USING BTREE,
        KEY `mid` (`mid`) USING BTREE
    ) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8mb4;");
}
